# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class ShareActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share)

        // Get the intent that started this activity
        val intent = intent

        if (Intent.ACTION_SEND == intent.action) {
            when {
                intent.type?.startsWith("image/") == true -> {
                    // Handle shared image
                    val imageUri: Uri? = intent.getParcelableExtra(Intent.EXTRA_STREAM)
                    processImage(imageUri)
                }
                intent.type?.equals("text/plain") == true -> {
                    // Handle shared text (URL)
                    val url: String? = intent.getStringExtra(Intent.EXTRA_TEXT)
                    processUrl(url)
                }
            }
        }
    }

    private fun processImage(uri: Uri?) {
        uri?.let {
            Toast.makeText(this, "Received image from share", Toast.LENGTH_SHORT).show()
            // Add your image processing logic here
        } ?: run {
            Toast.makeText(this, "No valid image received", Toast.LENGTH_SHORT).show()
        }
    }

    private fun processUrl(url: String?) {
        url?.let {
            Toast.makeText(this, "Received URL from share: $url", Toast.LENGTH_SHORT).show()
            // Add your URL processing logic here
        } ?: run {
            Toast.makeText(this, "No valid URL received", Toast.LENGTH_SHORT).show()
        }
    }
}